import{_ as i,z as o,m as s,ap as e}from"./chunks/framework.bQJNM8pB.js";const p=JSON.parse('{"title":"配置项说明","description":"","frontmatter":{},"headers":[],"relativePath":"markdown/start/config.md","filePath":"markdown/start/config.md","lastUpdated":1777129582000}'),l={name:"markdown/start/config.md"};function t(n,a,r,h,d,c){return s(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h1><p><code>adapter-yunhupro</code> 适配器的所有配置都在 Koishi 的插件配置页面中完成。</p><p>本页将详细介绍每个配置项的含义和用法。</p><h2 id="订阅配置" tabindex="-1">订阅配置 <a class="header-anchor" href="#订阅配置" aria-label="Permalink to &quot;订阅配置&quot;">​</a></h2><h3 id="机器人-token" tabindex="-1">机器人 Token (<code>token</code>) <a class="header-anchor" href="#机器人-token" aria-label="Permalink to &quot;机器人 Token (`token`)&quot;">​</a></h3><ul><li><strong><code>token</code></strong>: (字符串) <ul><li><strong>描述</strong>: 填写您在云湖平台获取的机器人 <strong>Token</strong>。请妥善保管，不要泄露。</li><li><strong>必填</strong>: 是</li><li><strong>类型</strong>: 密钥（输入时会隐藏）</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>无需填写机器人 ID</strong></p><p>新版本会在启动时自动获取机器人 ID，您只需要提供 Token 即可。</p></div><h3 id="订阅方式" tabindex="-1">订阅方式 (<code>type</code>) <a class="header-anchor" href="#订阅方式" aria-label="Permalink to &quot;订阅方式 (`type`)&quot;">​</a></h3><ul><li><strong><code>type</code></strong>: (选择) <ul><li><strong>描述</strong>: 选择与云湖平台的连接方式。</li><li><strong>默认值</strong>: <code>websocket</code></li><li><strong>可选值</strong>: <ul><li><code>websocket</code>: WebSocket 长连接方式（推荐）</li><li><code>webhook</code>: Webhook 推送方式</li></ul></li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>推荐使用 WebSocket 方式</strong></p><ul><li>✅ 无需公网 IP</li><li>✅ 配置简单</li><li>✅ 不会出现消息混乱</li><li>✅ 支持自动重连</li></ul></div><h3 id="websocket-配置" tabindex="-1">WebSocket 配置 <a class="header-anchor" href="#websocket-配置" aria-label="Permalink to &quot;WebSocket 配置&quot;">​</a></h3><p>当 <code>type</code> 选择为 <code>websocket</code> 时，需要配置以下项：</p><ul><li><strong><code>serverPath</code></strong>: (字符串) <ul><li><strong>描述</strong>: 云湖 WebSocket 服务器地址。</li><li><strong>默认值</strong>: <code>wss://ws.jwzhd.com/subscribe</code></li><li><strong>建议</strong>: 通常无需修改</li></ul></li></ul><h3 id="webhook-配置" tabindex="-1">Webhook 配置 <a class="header-anchor" href="#webhook-配置" aria-label="Permalink to &quot;Webhook 配置&quot;">​</a></h3><p>当 <code>type</code> 选择为 <code>webhook</code> 时，需要配置以下项：</p><ul><li><strong><code>path</code></strong>: (字符串) <ul><li><strong>描述</strong>: 本机接收 Webhook 事件的监听路径。</li><li><strong>默认值</strong>: <code>/yunhu</code></li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>关于 Webhook 路径的重要说明</strong></p><p>使用 Webhook 方式时，如果您需要运行多个云湖机器人实例：</p><ul><li>每个实例必须配置<strong>不同的监听路径</strong></li><li>相同的路径会导致消息混乱</li></ul><p><strong>推荐做法</strong>：使用 Koishi 的多开插件功能，为每个机器人实例配置不同的路径。</p><p>例如：</p><ul><li>机器人实例 1：<code>/yunhu1</code></li><li>机器人实例 2：<code>/yunhu2</code></li></ul><p><strong>为什么会混乱？</strong></p><p>云湖的 Webhook 推送没有身份验证机制，使用相同路径会导致所有机器人收到相同的消息。</p></div><h2 id="进阶设置" tabindex="-1">进阶设置 <a class="header-anchor" href="#进阶设置" aria-label="Permalink to &quot;进阶设置&quot;">​</a></h2><h3 id="文件上传超时时间" tabindex="-1">文件上传超时时间 (<code>uploadTimeout</code>) <a class="header-anchor" href="#文件上传超时时间" aria-label="Permalink to &quot;文件上传超时时间 (`uploadTimeout`)&quot;">​</a></h3><ul><li><strong><code>uploadTimeout</code></strong>: (数字) <ul><li><strong>描述</strong>: 下载/上传文件的超时时间（秒）。</li><li><strong>默认值</strong>: <code>120</code></li><li><strong>范围</strong>: 30-3600 秒</li><li><strong>步长</strong>: 1 秒</li></ul></li></ul><h3 id="音频背景颜色" tabindex="-1">音频背景颜色 (<code>audioBackgroundColor</code>) <a class="header-anchor" href="#音频背景颜色" aria-label="Permalink to &quot;音频背景颜色 (`audioBackgroundColor`)&quot;">​</a></h3><ul><li><strong><code>audioBackgroundColor</code></strong>: (字符串) <ul><li><strong>描述</strong>: 音频转为视频时使用的背景颜色。</li><li><strong>默认值</strong>: <code>rgba(0, 0, 0, 1)</code></li><li><strong>注意</strong>: 仅RGB通道生效，A通道（透明度）不生效</li></ul></li></ul><h2 id="网络请求设置" tabindex="-1">网络请求设置 <a class="header-anchor" href="#网络请求设置" aria-label="Permalink to &quot;网络请求设置&quot;">​</a></h2><h3 id="最大重试次数" tabindex="-1">最大重试次数 (<code>maxRetries</code>) <a class="header-anchor" href="#最大重试次数" aria-label="Permalink to &quot;最大重试次数 (`maxRetries`)&quot;">​</a></h3><ul><li><strong><code>maxRetries</code></strong>: (数字) <ul><li><strong>描述</strong>: 网络请求失败时的最大重试次数。</li><li><strong>默认值</strong>: <code>3</code></li><li><strong>范围</strong>: 1-10 次</li><li><strong>步长</strong>: 1 次</li></ul></li></ul><h2 id="流式消息设置" tabindex="-1">流式消息设置 <a class="header-anchor" href="#流式消息设置" aria-label="Permalink to &quot;流式消息设置&quot;">​</a></h2><h3 id="是否开启流式消息" tabindex="-1">是否开启流式消息 (<code>enableStream</code>) <a class="header-anchor" href="#是否开启流式消息" aria-label="Permalink to &quot;是否开启流式消息 (`enableStream`)&quot;">​</a></h3><ul><li><strong><code>enableStream</code></strong>: (布尔值) <ul><li><strong>描述</strong>: 是否开启流式消息。开启后，文本、Markdown消息将以流式消息方式发送。</li><li><strong>默认值</strong>: <code>false</code></li><li><strong>实验性功能</strong>: 是</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>流式消息是实验性功能，不推荐在生产环境中开启。</p></div><h3 id="流式消息总时长" tabindex="-1">流式消息总时长 (<code>streamDuration</code>) <a class="header-anchor" href="#流式消息总时长" aria-label="Permalink to &quot;流式消息总时长 (`streamDuration`)&quot;">​</a></h3><ul><li><strong><code>streamDuration</code></strong>: (数字) <ul><li><strong>描述</strong>: 流式消息总时长（秒）。数值越小，发消息越快。流式消息将被标记为<code>本内容为AI生成，仅供参考</code>。</li><li><strong>默认值</strong>: <code>2</code></li><li><strong>范围</strong>: 1-10 秒</li><li><strong>步长</strong>: 1 秒</li><li><strong>注意</strong>: 仅在 <code>enableStream</code> 为 <code>true</code> 时生效</li></ul></li></ul><h2 id="界面设置" tabindex="-1">界面设置 <a class="header-anchor" href="#界面设置" aria-label="Permalink to &quot;界面设置&quot;">​</a></h2><h3 id="显示云湖控制台入口" tabindex="-1">显示云湖控制台入口 (<code>showConsole</code>) <a class="header-anchor" href="#显示云湖控制台入口" aria-label="Permalink to &quot;显示云湖控制台入口 (`showConsole`)&quot;">​</a></h3><ul><li><strong><code>showConsole</code></strong>: (布尔值) <ul><li><strong>描述</strong>: 是否在侧边栏显示云湖控制台入口。</li><li><strong>默认值</strong>: <code>false</code></li></ul></li></ul><h2 id="连接设置" tabindex="-1">连接设置 <a class="header-anchor" href="#连接设置" aria-label="Permalink to &quot;连接设置&quot;">​</a></h2><p>这些是与云湖 API 服务器连接相关的设置。</p><p>通常情况下，您<strong>不需要修改</strong>这些默认值。</p><ul><li><p><strong><code>endpoint</code></strong>: (字符串)</p><ul><li><strong>描述</strong>: 云湖开放平台 API 的主地址。</li><li><strong>默认值</strong>: <code>https://chat-go.jwzhd.com/open-apis/v1</code></li></ul></li><li><p><strong><code>endpointweb</code></strong>: (字符串)</p><ul><li><strong>描述</strong>: 云湖 Web API 的地址。</li><li><strong>默认值</strong>: <code>https://chat-web-go.jwzhd.com/v1</code></li></ul></li><li><p><strong><code>resourceEndpoint</code></strong>: (字符串)</p><ul><li><strong>描述</strong>: 资源服务器地址。</li><li><strong>默认值</strong>: <code>https://chat-img.jwznb.com/</code></li></ul></li></ul><h2 id="调试设置" tabindex="-1">调试设置 <a class="header-anchor" href="#调试设置" aria-label="Permalink to &quot;调试设置&quot;">​</a></h2><h3 id="日志调试模式" tabindex="-1">日志调试模式 (<code>loggerinfo</code>) <a class="header-anchor" href="#日志调试模式" aria-label="Permalink to &quot;日志调试模式 (`loggerinfo`)&quot;">​</a></h3><ul><li><strong><code>loggerinfo</code></strong>: (布尔值) <ul><li><strong>描述</strong>: 日志调试模式。开启后会输出详细的调试日志。</li><li><strong>默认值</strong>: <code>false</code></li><li><strong>实验性功能</strong>: 是</li><li><strong>建议</strong>: 仅在需要进行问题排查时开启，以免产生过多的日志。</li></ul></li></ul><h2 id="多机器人配置" tabindex="-1">多机器人配置 <a class="header-anchor" href="#多机器人配置" aria-label="Permalink to &quot;多机器人配置&quot;">​</a></h2><p>如果您需要运行多个云湖机器人，请使用 Koishi 的<strong>多开插件功能</strong>：</p><ol><li>在插件列表中找到 <code>adapter-yunhupro</code></li><li>点击「添加实例」按钮</li><li>为每个实例配置不同的 Token</li></ol><h3 id="websocket-方式" tabindex="-1">WebSocket 方式 <a class="header-anchor" href="#websocket-方式" aria-label="Permalink to &quot;WebSocket 方式&quot;">​</a></h3><p>每个实例会独立建立 WebSocket 连接，无需额外配置，不会出现消息混乱。</p><h3 id="webhook-方式" tabindex="-1">Webhook 方式 <a class="header-anchor" href="#webhook-方式" aria-label="Permalink to &quot;Webhook 方式&quot;">​</a></h3><p>每个实例必须配置不同的监听路径（<code>path</code>），否则会导致消息混乱。</p><h2 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h2><h3 id="websocket-方式-推荐" tabindex="-1">WebSocket 方式（推荐） <a class="header-anchor" href="#websocket-方式-推荐" aria-label="Permalink to &quot;WebSocket 方式（推荐）&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">token</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">&quot;your_bot_token_here&quot;</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">websocket</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">serverPath</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">wss://ws.jwzhd.com/subscribe</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">loggerinfo</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">false</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">uploadTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">120</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">enableStream</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">false</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">maxRetries</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">3</span></span></code></pre></div><h3 id="webhook-方式-1" tabindex="-1">Webhook 方式 <a class="header-anchor" href="#webhook-方式-1" aria-label="Permalink to &quot;Webhook 方式&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">token</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">&quot;your_bot_token_here&quot;</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">webhook</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">path</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;">/yunhu</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">loggerinfo</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">false</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">uploadTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">120</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">enableStream</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">false</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#E06C75;">maxRetries</span><span style="--shiki-light:#24292E;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#D19A66;">3</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么推荐使用-websocket-方式" tabindex="-1">Q: 为什么推荐使用 WebSocket 方式？ <a class="header-anchor" href="#q-为什么推荐使用-websocket-方式" aria-label="Permalink to &quot;Q: 为什么推荐使用 WebSocket 方式？&quot;">​</a></h3><p>A: WebSocket 方式有以下优势：</p><ul><li>无需公网 IP，本地开发更方便</li><li>不会出现消息混乱问题</li><li>支持自动重连，连接更稳定</li><li>配置更简单</li></ul><h3 id="q-我可以同时使用-websocket-和-webhook-吗" tabindex="-1">Q: 我可以同时使用 WebSocket 和 Webhook 吗？ <a class="header-anchor" href="#q-我可以同时使用-websocket-和-webhook-吗" aria-label="Permalink to &quot;Q: 我可以同时使用 WebSocket 和 Webhook 吗？&quot;">​</a></h3><p>A: 不可以。每个机器人实例只能选择一种连接方式。如果需要使用不同的连接方式，请创建多个插件实例。</p><h3 id="q-webhook-方式什么时候使用" tabindex="-1">Q: Webhook 方式什么时候使用？ <a class="header-anchor" href="#q-webhook-方式什么时候使用" aria-label="Permalink to &quot;Q: Webhook 方式什么时候使用？&quot;">​</a></h3><p>A: 如果您的部署环境有以下特点，可以考虑使用 Webhook：</p><ul><li>已经有公网 IP 或域名</li><li>需要通过反向代理进行流量管理</li><li>有特殊的网络架构要求</li></ul><h3 id="q-如何知道机器人的-id" tabindex="-1">Q: 如何知道机器人的 ID？ <a class="header-anchor" href="#q-如何知道机器人的-id" aria-label="Permalink to &quot;Q: 如何知道机器人的 ID？&quot;">​</a></h3><p>A: 启动适配器后，查看 Koishi 控制台日志，会显示自动获取到的机器人 ID。您也可以在云湖客户端中查看机器人的个人资料。</p>',64)])])}const g=i(l,[["render",t]]);export{p as __pageData,g as default};
